// Generated by Claude Opus 4.6

import { BackupItem } from '@eclipse-che/common';
import userEvent from '@testing-library/user-event';
import React from 'react';
import { Provider } from 'react-redux';

import getComponentRenderer, { screen, waitFor } from '@/services/__mocks__/getComponentRenderer';
import { che } from '@/services/models';
import { MockStoreBuilder } from '@/store/__mocks__/mockStore';

import { RestoreFromBackupPage } from '..';

jest.mock('@/components/EditorSelector');

const mockWindowOpen = jest.fn();
Object.defineProperty(window, 'open', { value: mockWindowOpen, writable: true });

const mockNavigate = jest.fn();
const mockFetchBackupList = jest.fn();
const mockFetchBackupConfig = jest.fn();
const mockRestoreFromBackup = jest.fn();

const defaultNamespace: che.KubernetesNamespace = {
  name: 'user-namespace',
  attributes: {
    default: 'true',
    phase: 'Active',
  },
};

const mockBackups: BackupItem[] = [
  {
    workspaceName: 'my-workspace',
    imageUrl: 'image-registry.openshift-image-registry.svc:5000/user-namespace/my-workspace:latest',
    timestamp: '2026-02-11T12:00:00Z',
    sizeBytes: 1024,
    workspaceExists: true,
    labels: {},
  },
  {
    workspaceName: 'old-workspace',
    imageUrl:
      'image-registry.openshift-image-registry.svc:5000/user-namespace/old-workspace:latest',
    timestamp: '2026-02-10T12:00:00Z',
    sizeBytes: 2048,
    workspaceExists: false,
    labels: {},
  },
];

const mockBackupConfig = {
  enabled: true,
  schedule: '0 1 * * *',
  registry: 'image-registry.openshift-image-registry.svc:5000',
  backupSchedule: '0 1 * * *',
};

const { createSnapshot, renderComponent } = getComponentRenderer(getComponent);

// Helper to get default-registry workspace name input (first in DOM)
const getDefaultRegistryWorkspaceNameInput = () => {
  return screen.getAllByLabelText('Workspace name')[0];
};

// Helper to get the visible restore submit button (handles duplicate test IDs from both forms)
const getRestoreSubmitButton = () => {
  return screen.getAllByTestId('restore-submit-button')[0];
};

describe('RestoreFromBackupPage', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('initial rendering', () => {
    test('should render page with title', () => {
      renderComponent();

      expect(screen.getByText('Restore from Backup')).toBeInTheDocument();
    });

    test('should render accordion with both modes', () => {
      renderComponent();

      expect(screen.getByRole('button', { name: /Default registry/i })).toBeInTheDocument();
      expect(screen.getByRole('button', { name: /External registry/i })).toBeInTheDocument();
    });

    test('should have default-registry expanded by default', () => {
      renderComponent();

      const defaultRegistryButton = screen.getByRole('button', { name: /Default registry/i });
      expect(defaultRegistryButton).toHaveAttribute('aria-expanded', 'true');
    });

    test('should render restore button', () => {
      renderComponent();

      expect(getRestoreSubmitButton()).toBeInTheDocument();
    });

    test('should have restore button disabled initially', () => {
      renderComponent();

      expect(getRestoreSubmitButton()).toBeDisabled();
    });

    test('should fetch backup list on mount', () => {
      renderComponent();

      expect(mockFetchBackupList).toHaveBeenCalledWith({ namespace: 'user-namespace' });
    });

    test('should fetch backup config on mount', () => {
      renderComponent();

      expect(mockFetchBackupConfig).toHaveBeenCalledWith({ namespace: 'user-namespace' });
    });

    test('snapshot - initial state', () => {
      const snapshot = createSnapshot();
      expect(snapshot.toJSON()).toMatchSnapshot();
    });
  });

  describe('default-registry mode', () => {
    test('should display workspace name input', () => {
      renderComponent();

      expect(getDefaultRegistryWorkspaceNameInput()).toBeInTheDocument();
    });

    test('should enable restore button when valid workspace name is entered', async () => {
      renderComponent();

      const input = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(input);
      await userEvent.type(input, 'my-workspace');

      // Wait for input value to be updated
      await waitFor(() => expect(input).toHaveValue('my-workspace'));

      // Wait for button to become enabled
      await waitFor(
        () => {
          expect(getRestoreSubmitButton()).not.toBeDisabled();
        },
        { timeout: 2000 },
      );
    });

    test('should not display image preview when only workspace name is entered', async () => {
      // Image preview is not shown when only a workspace name is typed — the backend
      // derives the image URL from cluster registry configuration at restore time.
      renderComponent();

      const input = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(input);
      await userEvent.type(input, 'my-workspace');

      expect(screen.queryByTestId('image-preview')).not.toBeInTheDocument();
    });

    test('should show backup dropdown when backups exist', () => {
      renderComponent({ backups: mockBackups });

      expect(screen.getByText('Select a backup to restore')).toBeInTheDocument();
    });

    // Generated by Claude Opus 4.6
    test('should show error and disable restore when active backup is selected', async () => {
      const existingWorkspaceNames = new Set(['my-workspace']);
      renderComponent({ backups: mockBackups, existingWorkspaceNames });

      // Open the select dropdown and pick the backup where workspaceExists=true
      const selectToggle = screen.getByText('Select a backup to restore');
      await userEvent.click(selectToggle);

      const option = screen.getByText('my-workspace (Active)');
      await userEvent.click(option);

      // Wait for workspace name to be populated
      const nameInput = getDefaultRegistryWorkspaceNameInput();
      await waitFor(() => {
        expect(nameInput).toHaveValue('my-workspace');
      });

      // Error shown — workspace already exists
      await waitFor(
        () => {
          expect(
            screen.getByText('A workspace with this name already exists.'),
          ).toBeInTheDocument();
        },
        { timeout: 3000 },
      );

      // Restore button is disabled in error state
      expect(getRestoreSubmitButton()).toBeDisabled();
    });

    // Generated by Claude Sonnet 4.5
    test('should disable Restore button and show error when workspace name conflicts with existing workspace', async () => {
      const existingWorkspaceNames = new Set(['existing-workspace']);
      renderComponent({ backups: [], existingWorkspaceNames });

      const input = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(input);
      await userEvent.type(input, 'existing-workspace');

      // Wait for validation to complete
      await waitFor(() => {
        expect(screen.getByText('A workspace with this name already exists.')).toBeInTheDocument();
      });

      expect(getRestoreSubmitButton()).toBeDisabled();
    });

    // Generated by Claude Sonnet 4.5
    test('should allow restore when workspace name does not conflict', async () => {
      const existingWorkspaceNames = new Set(['existing-workspace']);
      renderComponent({ backups: [], existingWorkspaceNames });

      const input = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(input);
      await userEvent.type(input, 'new-workspace');

      // Wait for validation to complete
      await waitFor(() => {
        expect(input).toHaveValue('new-workspace');
      });

      // Should not show error message
      expect(
        screen.queryByText('A workspace with this name already exists.'),
      ).not.toBeInTheDocument();
    });

    // Generated by Claude Sonnet 4.6
    test('should enable Restore button when selectedBackup.workspaceExists is false', async () => {
      renderComponent({ backups: mockBackups });

      // Open the select dropdown and pick the backup where workspaceExists=false
      const selectToggle = screen.getByText('Select a backup to restore');
      await userEvent.click(selectToggle);

      const option = screen.getByText('old-workspace (Deleted)');
      await userEvent.click(option);

      expect(getRestoreSubmitButton()).not.toBeDisabled();
    });

    // After changing the name away from conflict, button should re-enable
    test('should enable Restore button when active backup is selected but name is changed', async () => {
      const existingWorkspaceNames = new Set(['my-workspace']);
      renderComponent({ backups: mockBackups, existingWorkspaceNames });

      // Select the active backup (workspaceExists=true, name auto-fills to 'my-workspace')
      await userEvent.click(screen.getByText('Select a backup to restore'));
      await userEvent.click(screen.getByText('my-workspace (Active)'));

      // Wait for workspace name to be populated
      const nameInput = getDefaultRegistryWorkspaceNameInput();
      await waitFor(() => {
        expect(nameInput).toHaveValue('my-workspace');
      });

      // Button is disabled in error state — workspace already exists
      expect(getRestoreSubmitButton()).toBeDisabled();

      // Change the name — error resolved, button becomes enabled
      await userEvent.clear(nameInput);
      await userEvent.type(nameInput, 'my-workspace-new');

      await waitFor(() => {
        expect(getRestoreSubmitButton()).not.toBeDisabled();
      });
    });

    // Generated by Claude Opus 4.6
    test('should hide error when user provides a different workspace name', async () => {
      const existingWorkspaceNames = new Set(['my-workspace']);
      renderComponent({ backups: mockBackups, existingWorkspaceNames });

      await userEvent.click(screen.getByText('Select a backup to restore'));
      await userEvent.click(screen.getByText('my-workspace (Active)'));

      // Error visible with original name
      await waitFor(() => {
        expect(screen.getByText('A workspace with this name already exists.')).toBeInTheDocument();
      });

      const nameInput = getDefaultRegistryWorkspaceNameInput();
      await userEvent.clear(nameInput);
      await userEvent.type(nameInput, 'my-workspace-new');

      // Wait for validation
      await waitFor(() => {
        expect(nameInput).toHaveValue('my-workspace-new');
      });

      // Error gone — no conflict with new name
      expect(
        screen.queryByText('A workspace with this name already exists.'),
      ).not.toBeInTheDocument();
    });

    test('should keep selected backup when user overrides workspace name', async () => {
      renderComponent({ backups: mockBackups });

      // Select the deleted backup
      await userEvent.click(screen.getByText('Select a backup to restore'));
      await userEvent.click(screen.getByText('old-workspace (Deleted)'));

      // Wait for image preview to show selected backup URL
      await waitFor(() => {
        expect(screen.getByTestId('image-preview')).toHaveTextContent('old-workspace:latest');
      });

      // Override the name — backup should remain selected, image preview unchanged
      const nameInput = getDefaultRegistryWorkspaceNameInput();
      await userEvent.clear(nameInput);
      await userEvent.type(nameInput, 'my-new-name');

      expect(screen.getByTestId('image-preview')).toHaveTextContent('old-workspace:latest');
      expect(nameInput).toHaveValue('my-new-name');
    });

    test('should call restoreFromBackup with custom name and original backup image URL', async () => {
      mockRestoreFromBackup.mockResolvedValue(undefined);
      renderComponent({ backups: mockBackups });

      // Select the deleted backup
      await userEvent.click(screen.getByText('Select a backup to restore'));
      await userEvent.click(screen.getByText('old-workspace (Deleted)'));

      // Override the name
      const nameInput = getDefaultRegistryWorkspaceNameInput();
      await userEvent.clear(nameInput);
      await userEvent.type(nameInput, 'restored-as-new');

      // Wait for button to be enabled and click it
      const restoreButton = getRestoreSubmitButton();
      await waitFor(() => expect(restoreButton).not.toBeDisabled(), { timeout: 2000 });
      await userEvent.click(restoreButton);

      // No backup name conflict → restore fires directly without modal
      await waitFor(() => {
        expect(mockRestoreFromBackup).toHaveBeenCalledWith(
          'user-namespace',
          'restored-as-new',
          'image-registry.openshift-image-registry.svc:5000/user-namespace/old-workspace:latest',
          'che-incubator/che-code/latest',
          undefined,
          undefined,
        );
      });
    });

    test('should sanitize workspace name input', async () => {
      renderComponent();

      const input = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(input);
      await userEvent.type(input, 'My_Workspace');

      expect(input).toHaveValue('myworkspace');
    });

    test('should show error for invalid workspace name', async () => {
      renderComponent();

      const input = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(input);
      await userEvent.type(input, '-invalid');

      expect(
        screen.getByText(
          'Must contain only lowercase letters, numbers, and hyphens. Must start and end with a letter or number.',
        ),
      ).toBeInTheDocument();
    });
  });

  describe('external-registry mode', () => {
    test('should display image URL input when external-registry selected', async () => {
      renderComponent();

      const externalRegistryButton = screen.getByRole('button', { name: /External registry/i });
      await userEvent.click(externalRegistryButton);

      expect(screen.getByLabelText('Backup image URL')).toBeInTheDocument();
    });

    test('should enable restore button immediately when a valid URL is typed', async () => {
      renderComponent();

      const externalRegistryButton = screen.getByRole('button', { name: /External registry/i });
      await userEvent.click(externalRegistryButton);

      const input = screen.getByLabelText('Backup image URL');
      await userEvent.type(input, 'registry.example.com/ns/workspace:latest');

      await waitFor(() => {
        expect(getRestoreSubmitButton()).not.toBeDisabled();
      });
    });

    test('should auto-populate workspace name from URL last segment', async () => {
      renderComponent();

      await userEvent.click(screen.getByRole('button', { name: /External registry/i }));
      await userEvent.type(
        screen.getByLabelText('Backup image URL'),
        'registry.example.com/ns/my-workspace:latest',
      );

      const externalRegistryNameInput = document.getElementById('restore-workspace-name-cross');
      expect(externalRegistryNameInput).toHaveValue('my-workspace');
    });

    test('should allow editing the auto-populated workspace name in external-registry mode', async () => {
      renderComponent();

      await userEvent.click(screen.getByRole('button', { name: /External registry/i }));
      await userEvent.type(
        screen.getByLabelText('Backup image URL'),
        'registry.example.com/ns/workspace:latest',
      );

      const nameInput = document.getElementById('restore-workspace-name-cross');
      await userEvent.clear(nameInput!);
      await userEvent.type(nameInput!, 'custom-name');

      expect(nameInput).toHaveValue('custom-name');
    });
  });

  describe('initial image URL', () => {
    test('should pre-fill external-registry mode with initial external URL', () => {
      renderComponent({ initialExternalImageUrl: 'registry.example.com/ns/ws:latest' });

      const externalRegistryButton = screen.getByRole('button', { name: /External registry/i });
      expect(externalRegistryButton).toHaveAttribute('aria-expanded', 'true');

      const input = screen.getByLabelText('Backup image URL');
      expect(input).toHaveValue('registry.example.com/ns/ws:latest');
    });

    test('should pre-fill default-registry mode with initial backup URL', () => {
      renderComponent({
        initialBackupImageUrl:
          'image-registry.openshift-image-registry.svc:5000/user-namespace/my-workspace:latest',
      });

      const defaultRegistryButton = screen.getByRole('button', { name: /Default registry/i });
      expect(defaultRegistryButton).toHaveAttribute('aria-expanded', 'true');
    });
  });

  describe('confirmation modal', () => {
    test('should open confirmation modal when restore is clicked', async () => {
      // Modal only opens when workspace name conflicts with an existing backup
      renderComponent({ existingBackupNames: new Set(['my-workspace']) });

      const input = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(input);
      await userEvent.type(input, 'my-workspace');

      // Wait for button to be enabled
      const restoreButton = getRestoreSubmitButton();
      await waitFor(() => expect(restoreButton).not.toBeDisabled(), { timeout: 2000 });
      await userEvent.click(restoreButton);

      expect(screen.getByTestId('restore-confirmation-modal')).toBeInTheDocument();
      expect(screen.getByText('Confirm Restore from Backup')).toBeInTheDocument();
    });

    test('should show workspace name in confirmation modal', async () => {
      renderComponent({ existingBackupNames: new Set(['my-workspace']) });

      const input = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(input);
      await userEvent.type(input, 'my-workspace');

      // Wait for button to be enabled
      const restoreButton = getRestoreSubmitButton();
      await waitFor(() => expect(restoreButton).not.toBeDisabled(), { timeout: 2000 });
      await userEvent.click(restoreButton);

      expect(screen.getByTestId('confirm-workspace-name')).toHaveTextContent('my-workspace');
    });

    test('should close confirmation modal when cancel is clicked', async () => {
      renderComponent({ existingBackupNames: new Set(['my-workspace']) });

      const input = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(input);
      await userEvent.type(input, 'my-workspace');

      // Wait for button to be enabled
      const restoreButton = getRestoreSubmitButton();
      await waitFor(() => expect(restoreButton).not.toBeDisabled(), { timeout: 2000 });
      await userEvent.click(restoreButton);

      const cancelButton = screen.getByTestId('restore-confirm-cancel-button');
      await userEvent.click(cancelButton);

      expect(screen.queryByTestId('restore-confirmation-modal')).not.toBeInTheDocument();
    });

    test('should skip modal and call restore directly when workspace name has no backup conflict', async () => {
      mockRestoreFromBackup.mockResolvedValue(undefined);
      renderComponent({
        backups: [],
        existingBackupNames: new Set(['other-backup']),
      });

      // Switch to external-registry to easily set a valid form
      await userEvent.click(screen.getByRole('button', { name: /External registry/i }));
      await userEvent.type(
        screen.getByLabelText('Backup image URL'),
        'registry.example.com/ns/unique-workspace:latest',
      );

      await waitFor(() => {
        expect(getRestoreSubmitButton()).not.toBeDisabled();
      });

      await userEvent.click(getRestoreSubmitButton());

      // Modal should NOT appear
      expect(screen.queryByTestId('restore-confirmation-modal')).not.toBeInTheDocument();

      // Restore should be called directly
      await waitFor(() => {
        expect(mockRestoreFromBackup).toHaveBeenCalled();
      });
    });

    test('should show modal when workspace name matches an existing backup', async () => {
      renderComponent({
        backups: [],
        existingBackupNames: new Set(['my-workspace']),
      });

      // Switch to external-registry to easily set a valid form
      await userEvent.click(screen.getByRole('button', { name: /External registry/i }));
      await userEvent.type(
        screen.getByLabelText('Backup image URL'),
        'registry.example.com/ns/my-workspace:latest',
      );

      await waitFor(() => {
        expect(getRestoreSubmitButton()).not.toBeDisabled();
      });

      await userEvent.click(getRestoreSubmitButton());

      // Modal SHOULD appear
      expect(screen.getByTestId('restore-confirmation-modal')).toBeInTheDocument();
      expect(screen.getByTestId('backup-conflict-warning')).toBeInTheDocument();

      // Restore should NOT have been called yet
      expect(mockRestoreFromBackup).not.toHaveBeenCalled();
    });

    test('should call restoreFromBackup and navigate to workspaces on confirm', async () => {
      mockRestoreFromBackup.mockResolvedValue(undefined);
      // Modal only opens when workspace name conflicts with an existing backup
      renderComponent({ existingBackupNames: new Set(['my-workspace']) });

      const input = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(input);
      await userEvent.type(input, 'my-workspace');

      // Wait for button to be enabled
      const restoreButton = getRestoreSubmitButton();
      await waitFor(() => expect(restoreButton).not.toBeDisabled(), { timeout: 2000 });
      await userEvent.click(restoreButton);

      // Wait for modal to appear
      const confirmButton = await screen.findByTestId('restore-confirm-button');
      await userEvent.click(confirmButton);

      await waitFor(() => {
        // backupImageUrl is empty — backend derives it from cluster registry config
        expect(mockRestoreFromBackup).toHaveBeenCalledWith(
          'user-namespace',
          'my-workspace',
          '',
          'che-incubator/che-code/latest',
          undefined,
          undefined,
        );
      });

      await waitFor(() => {
        expect(mockWindowOpen).toHaveBeenCalledWith(
          expect.stringContaining('/ide/user-namespace/my-workspace'),
          '_blank',
        );
      });
    });
  });

  describe('mode switching', () => {
    test('should switch to external-registry mode when accordion item clicked', async () => {
      renderComponent();

      const nameInput = getDefaultRegistryWorkspaceNameInput();
      await userEvent.click(nameInput);
      await userEvent.type(nameInput, 'my-workspace');

      const externalRegistryButton = screen.getByRole('button', { name: /External registry/i });
      await userEvent.click(externalRegistryButton);

      // Cross-cluster accordion should be expanded
      expect(externalRegistryButton).toHaveAttribute('aria-expanded', 'true');
      // Same-cluster accordion should be collapsed
      const defaultRegistryButton = screen.getByRole('button', { name: /Default registry/i });
      expect(defaultRegistryButton).toHaveAttribute('aria-expanded', 'false');
    });

    test('should switch to default-registry mode when accordion item clicked', async () => {
      renderComponent();

      const externalRegistryButton = screen.getByRole('button', { name: /External registry/i });
      await userEvent.click(externalRegistryButton);

      const urlInput = screen.getByLabelText('Backup image URL');
      await userEvent.click(urlInput);
      await userEvent.type(urlInput, 'registry.example.com/ns/ws:tag');

      const defaultRegistryButton = screen.getByRole('button', { name: /Default registry/i });
      await userEvent.click(defaultRegistryButton);

      // Same-cluster accordion should be expanded
      expect(defaultRegistryButton).toHaveAttribute('aria-expanded', 'true');
      // Cross-cluster accordion should be collapsed
      expect(externalRegistryButton).toHaveAttribute('aria-expanded', 'false');
    });
  });
});

function getComponent(
  options: {
    backups?: BackupItem[];
    initialBackupImageUrl?: string;
    initialExternalImageUrl?: string;
    existingWorkspaceNames?: Set<string>;
    existingBackupNames?: Set<string>;
  } = {},
) {
  const store = new MockStoreBuilder().build();

  return (
    <Provider store={store}>
      <RestoreFromBackupPage
        defaultNamespace={defaultNamespace}
        backups={options.backups || []}
        defaultEditor="che-incubator/che-code/latest"
        backupConfig={mockBackupConfig}
        existingWorkspaceNames={options.existingWorkspaceNames || new Set()}
        existingBackupNames={options.existingBackupNames || new Set()}
        fetchBackupList={mockFetchBackupList}
        fetchBackupConfig={mockFetchBackupConfig}
        restoreFromBackup={mockRestoreFromBackup}
        navigate={mockNavigate}
        initialBackupImageUrl={options.initialBackupImageUrl}
        initialExternalImageUrl={options.initialExternalImageUrl}
      />
    </Provider>
  );
}
